 1→import type { MittwaldCliToolHandler } from '../../../../../types/mittwald/conversation.js';
 2→import { formatToolResponse } from '../../../../../utils/format-tool-response.js';
 3→import { createMailAddress, LibraryError } from '@mittwald-mcp/cli-core';
 4→import { sessionManager } from '../../../../../server/session-manager.js';
 5→import { getCurrentSessionId } from '../../../../../utils/execution-context.js';
 6→import { logger } from '../../../../../utils/logger.js';
 7→
 8→interface MittwaldMailAddressCreateArgs {
 9→  address: string;
10→  projectId?: string;
11→  quiet?: boolean;
12→  catchAll?: boolean;
13→  enableSpamProtection?: boolean;
14→  quota?: string;
15→  password?: string;
16→  randomPassword?: boolean;
17→  forwardTo?: string[];
18→}
19→
20→export const handleMittwaldMailAddressCreateCli: MittwaldCliToolHandler<MittwaldMailAddressCreateArgs> = async (args, sessionId) => {
21→  const effectiveSessionId = sessionId || getCurrentSessionId();
22→
23→  if (!effectiveSessionId) {
24→    return formatToolResponse('error', 'Session ID required');
25→  }
26→
27→  if (!args.address) {
28→    return formatToolResponse('error', 'address is required');
29→  }
30→
31→  if (!args.projectId) {
32→    return formatToolResponse('error', 'projectId is required');
33→  }
